#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


//vUv = vUvOriginal;
float corr = uTexSize.xy*texsize_noise_lq.zw;
vec2 uv1 = vec2(vUv.x-0.5,vUv.y-0.5)*uAspect.xy;

vec2 tmp = uv1;
tmp.x = vAngle*3; tmp.y = vRadius;
uv1 = tmp;

vec3 noise = (texture(sampler_noise_lq,corr*vUv/2+q23)+1);

vec3 ret1 = GetBlur1 (vUv)-.3;
vec3 crisp = texture(sampler_main, vUv+ret1*.01 ) + noise*0.1;
vec3 blur = GetBlur1 (vUv/4+.4*vec2(.3*ret1.x,ret1.y)) - noise*.1;

ret = -.4*blur + crisp;
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((uv1.xyy*q27
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q29
                     );
if(ret.x> q21*q3         && ret.x<= q24*q1        )ret.y -= (noise9).x*.5;
if(ret.y> q22*q1         && ret.y<= q25*q2        )ret.z -= (noise9).y*.5;
if(ret.z> q23*q2         && ret.z<= q26*q3        )ret.x -= (noise9).z*.5;

 ret *= 0.98 * pow(1-.01*q28*q28*vRadius,2);
  ret -= 0.04;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 d = uTexSize.zw*4;
    vec3 dx = ( 2*GetBlur1(vUv+vec2(1,0)*d)-2*GetBlur1(vUv-vec2(1,0)*d) )*0.5;
    vec3 dy = ( 2*GetBlur1(vUv+vec2(0,1)*d)-2*GetBlur1(vUv-vec2(0,1)*d) )*0.5;

vec2 uv_x = vUv- vec2(dx.x,dy.x)*uTexSize.zw*4 + vec2(dx.y,dy.y)*uTexSize.zw*32;
ret = mix(GetBlur2(vUv).x,GetBlur3(vUv).x,0.6) + (GetPixel(uv_x).x-GetBlur1(uv_x).x)*1;
ret =sqrt(ret);
ret = 1- ret;
ret *= mix(vec3(2,1,0),vec3(0.5,1,2),(vUv.x+vUv.y)*0.5);
ret = mix(ret,vec3(2,1,0),GetBlur2(vUv + vec2(dx.y,dy.y)*0.1).y*2);
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((uv_x.xyy*q28
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q31
                     );
if(ret.x> q26*q3         && ret.x<= q23*q1        )ret.z -= (noise9).x*.5;
if(ret.y> q25*q1         && ret.y<= q22*q2        )ret.x -= (noise9).y*.5;
if(ret.z> q24*q2         && ret.z<= q21*q3        )ret.y -= (noise9).z*.5;
ret = mix(ret,length(vec2(dx.x,dy.x)) + GetPixel(vUv).x,GetBlur1(vUv).y*1.2);


  fragColor = ret;
}
